/* Includes */
#include <errno.h>
#include <stdint.h>
#include <stddef.h>

/**
 * Pointer to the current high watermark of the heap usage
 */
static uint8_t *__sbrk_heap_end = NULL;

/**
 * @brief _sbrk() allocates memory to the newlib heap and is used by malloc
 *        and others from the C library
 *
 * @verbatim
 * ############################################################################
 * #                    AXI SRAM                    #         DTCM RAM         #
 * # .heap_axi (newlib heap reserved by linker)    #   MSP stack reservation  #
 * ############################################################################
 * ^-- _heap_start                     _heap_end --^
 * @endverbatim
 *
 * This implementation uses the dedicated AXI SRAM heap region delimited by the
 * '_heap_start' and '_heap_end' linker symbols.
 *
 * @param incr Memory size
 * @return Pointer to allocated memory
 */
void *_sbrk(ptrdiff_t incr)
{
  extern uint8_t _heap_start; /* Symbol defined in the linker script */
  extern uint8_t _heap_end; /* Symbol defined in the linker script */
  const uint8_t *max_heap = &_heap_end;
  uint8_t *prev_heap_end;

  /* Initialize heap end at first call */
  if (NULL == __sbrk_heap_end)
  {
    __sbrk_heap_end = &_heap_start;
  }

  /* Protect heap from growing into the reserved MSP stack */
  if (__sbrk_heap_end + incr > max_heap)
  {
    errno = ENOMEM;
    return (void *)-1;
  }

  prev_heap_end = __sbrk_heap_end;
  __sbrk_heap_end += incr;

  return (void *)prev_heap_end;
}

#if defined(__PICOLIBC__)
  // Picolibc expects syscalls without the leading underscore.
  // This creates a strong alias so that
  // calls to `sbrk()` are resolved to our `_sbrk()` implementation.
  __strong_reference(_sbrk, sbrk);
#endif
